import { useStore } from './store';

export const SubmitButton = () => {
  const { nodes, edges } = useStore();

  const handleSubmit = async () => {
    // 1. Prepare data - FastAPI Form requires these to be sent as JSON strings
    const nodeIds = nodes.map(n => n.id);
    const edgeStrings = edges.map(e => `${e.source}->${e.target}`);

    const formData = new FormData();
    formData.append('nodes', JSON.stringify(nodeIds));
    formData.append('edges', JSON.stringify(edgeStrings));

    try {
      const response = await fetch('http://127.0.0.1:8000/pipelines/parse', {
        method: 'POST',
        body: formData, // Sending as multipart/form-data
      });

      if (!response.ok) {
        throw new Error(`Server returned ${response.status}`);
      }

      const data = await response.json();
      alert(`Pipeline Statistics:\nNodes: ${data.num_nodes}\nEdges: ${data.num_edges}\nIs DAG: ${data.is_dag}`);

    } catch (error) {
      console.error("Submit Error:", error);
      alert("Error: Could not connect to backend. Ensure Uvicorn is running on port 8000.");
    }
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', marginTop: '20px' }}>
      <button onClick={handleSubmit} style={{ padding: '10px 20px', cursor: 'pointer' }}>
        Submit Pipeline
      </button>
    </div>
  );
};
